SELECT date, low_temp
FROM weather_records
ORDER BY date;

SELECT weather_condition, COUNT(*) AS count
FROM weather_records
GROUP BY weather_condition;

SELECT COUNT(*) AS record_count
FROM weather_records
WHERE location_id = 1;

SELECT date, excess_rainfall, low_temp, high_temp
FROM weather_records
WHERE date >= '2023-01-01' AND date <= '2023-12-31';

SELECT date, low_temp, high_temp
FROM weather_records
ORDER BY date DESC;

SELECT COUNT(*) AS total_research_access
FROM research_access
WHERE access_type = 'view' AND access_date BETWEEN '2023-01-01' AND '2023-12-31';
